  1â†’import {
  2â†’	createContext,
  3â†’	type ReactNode,
  4â†’	useContext,
  5â†’	useEffect,
  6â†’	useState,
  7â†’} from "react";
  8â†’import { useSearchParams } from "react-router-dom";
  9â†’
 10â†’interface DateRangeContextType {
 11â†’	startDate: string;
 12â†’	endDate: string;
 13â†’	setStartDate: (date: string) => void;
 14â†’	setEndDate: (date: string) => void;
 15â†’	calculateDays: () => number;
 16â†’}
 17â†’
 18â†’const DateRangeContext = createContext<DateRangeContextType | undefined>(
 19â†’	undefined,
 20â†’);
 21â†’
 22â†’const STORAGE_KEY = "dateRange";
 23â†’
 24â†’const getDefaultDates = () => {
 25â†’	const end = new Date();
 26â†’	const start = new Date();
 27â†’	start.setDate(start.getDate() - 7);
 28â†’	return {
 29â†’		start: start.toISOString().split("T")[0],
 30â†’		end: end.toISOString().split("T")[0],
 31â†’	};
 32â†’};
 33â†’
 34â†’const getInitialDates = (searchParams: URLSearchParams) => {
 35â†’	const fromParam = searchParams.get("from");
 36â†’	const toParam = searchParams.get("to");
 37â†’	if (fromParam && toParam) {
 38â†’		return { start: fromParam, end: toParam };
 39â†’	}
 40â†’
 41â†’	try {
 42â†’		const stored = localStorage.getItem(STORAGE_KEY);
 43â†’		if (stored) {
 44â†’			const parsed = JSON.parse(stored);
 45â†’			if (parsed.start && parsed.end) {
 46â†’				return parsed;
 47â†’			}
 48â†’		}
 49â†’	} catch {
 50â†’		// Ignore localStorage errors
 51â†’	}
 52â†’
 53â†’	return getDefaultDates();
 54â†’};
 55â†’
 56â†’export function DateRangeProvider({ children }: { children: ReactNode }) {
 57â†’	const [searchParams, setSearchParams] = useSearchParams();
 58â†’
 59â†’	const initialDates = getInitialDates(searchParams);
 60â†’	const [startDate, setStartDateInternal] = useState(initialDates.start);
 61â†’	const [endDate, setEndDateInternal] = useState(initialDates.end);
 62â†’	const [isInitialized, setIsInitialized] = useState(false);
 63â†’
 64â†’	useEffect(() => {
 65â†’		const dates = getInitialDates(searchParams);
 66â†’		setStartDateInternal(dates.start);
 67â†’		setEndDateInternal(dates.end);
 68â†’		setIsInitialized(true);
 69â†’	}, [searchParams]);
 70â†’
 71â†’	useEffect(() => {
 72â†’		if (!isInitialized) return;
 73â†’
 74â†’		try {
 75â†’			localStorage.setItem(
 76â†’				STORAGE_KEY,
 77â†’				JSON.stringify({ start: startDate, end: endDate }),
 78â†’			);
 79â†’		} catch {
 80â†’			// Ignore localStorage errors
 81â†’		}
 82â†’
 83â†’		setSearchParams(
 84â†’			(prev) => {
 85â†’				prev.set("from", startDate);
 86â†’				prev.set("to", endDate);
 87â†’				return prev;
 88â†’			},
 89â†’			{ replace: true },
 90â†’		);
 91â†’	}, [startDate, endDate, isInitialized, setSearchParams]);
 92â†’
 93â†’	const setStartDate = (date: string) => {
 94â†’		setStartDateInternal(date);
 95â†’	};
 96â†’
 97â†’	const setEndDate = (date: string) => {
 98â†’		setEndDateInternal(date);
 99â†’	};
100â†’
101â†’	const calculateDays = () => {
102â†’		const startTime = new Date(startDate).getTime();
103â†’		const endTime = new Date(endDate).getTime();
104â†’		return Math.ceil((endTime - startTime) / (1000 * 60 * 60 * 24));
105â†’	};
106â†’
107â†’	return (
108â†’		<DateRangeContext.Provider
109â†’			value={{
110â†’				startDate,
111â†’				endDate,
112â†’				setStartDate,
113â†’				setEndDate,
114â†’				calculateDays,
115â†’			}}
116â†’		>
117â†’			{children}
118â†’		</DateRangeContext.Provider>
119â†’	);
120â†’}
121â†’
122â†’export function useDateRange() {
123â†’	const context = useContext(DateRangeContext);
124â†’	if (context === undefined) {
125â†’		throw new Error("useDateRange must be used within a DateRangeProvider");
126â†’	}
127â†’	return context;
128â†’}
