122â†’const deleteOrganization = os.deleteOrganization
123â†’	.use(authMiddleware)
124â†’	.handler(async ({ input, context }) => {
125â†’		const orgId = input.organizationId;
126â†’		const userId = context.user.id;
127â†’		console.log(
128â†’			`[deleteOrganization] user=${userId} org=${orgId} migrateSessionsTo=${input.migrateSessionsTo ?? "none"}`,
129â†’		);
130â†’
131â†’		// Check user has more than one org
132â†’		const memberships = await db
133â†’			.select({ organizationId: member.organizationId })
134â†’			.from(member)
135â†’			.where(eq(member.userId, userId));
136â†’
137â†’		if (memberships.length <= 1) {
138â†’			console.log(
139â†’				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
140â†’			);
141â†’			throw new ORPCError("BAD_REQUEST", {
142â†’				message: "Cannot delete your only organization",
143â†’			});
144â†’		}
145â†’
146â†’		// Verify user is owner of the target org
147â†’		const ownership = await db
148â†’			.select({ id: member.id })
149â†’			.from(member)
150â†’			.where(
151â†’				and(
152â†’					eq(member.organizationId, orgId),
153â†’					eq(member.userId, userId),
154â†’					eq(member.role, "owner"),
155â†’				),
156â†’			)
157â†’			.limit(1);
158â†’
159â†’		if (ownership.length === 0) {
160â†’			console.log(
161â†’				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
162â†’			);
163â†’			throw new ORPCError("FORBIDDEN", {
164â†’				message: "Only the organization owner can delete it",
165â†’			});
166â†’		}
167â†’
168â†’		try {
169â†’			if (input.migrateSessionsTo) {
170â†’				if (input.migrateSessionsTo === orgId) {
171â†’					throw new ORPCError("BAD_REQUEST", {
172â†’						message: "Cannot migrate sessions to the same organization",
173â†’					});
174â†’				}
175â†’
176â†’				// Verify user is a member of the target org
177â†’				const targetMembership = await db
178â†’					.select({ id: member.id })
179â†’					.from(member)
180â†’					.where(
181â†’						and(
182â†’							eq(member.organizationId, input.migrateSessionsTo),
183â†’							eq(member.userId, userId),
184â†’						),
185â†’					)
186â†’					.limit(1);
187â†’
188â†’				if (targetMembership.length === 0) {
189â†’					console.log(
190â†’						`[deleteOrganization] rejected: user=${userId} not member of target org=${input.migrateSessionsTo}`,
191â†’					);
192â†’					throw new ORPCError("FORBIDDEN", {
193â†’						message: "Not a member of the target organization",
194â†’					});
195â†’				}
196â†’
197â†’				console.log(
198â†’					`[deleteOrganization] migrating sessions from org=${orgId} to org=${input.migrateSessionsTo}`,
199â†’				);
200â†’				await migrateOrgSessions(orgId, input.migrateSessionsTo);
201â†’				console.log(`[deleteOrganization] session migration complete`);
202â†’			} else {
203â†’				console.log(
204â†’					`[deleteOrganization] deleting ClickHouse sessions for org=${orgId}`,
205â†’				);
206â†’				await deleteOrgSessions(orgId);
207â†’				console.log(
208â†’					`[deleteOrganization] ClickHouse session deletion complete`,
209â†’				);
210â†’			}
211â†’
212â†’			// Delete the organization from Postgres (cascade handles member + invitation)
213â†’			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
214â†’			await db.delete(organization).where(eq(organization.id, orgId));
215â†’
216â†’			// Clear activeOrganizationId on user sessions that reference the deleted org
217â†’			console.log(
218â†’				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
219â†’			);
220â†’			await db
221â†’				.update(session)
222â†’				.set({ activeOrganizationId: null })
223â†’				.where(eq(session.activeOrganizationId, orgId));
224â†’
225â†’			console.log(`[deleteOrganization] success for org=${orgId}`);
226â†’			return { success: true as const };
227â†’		} catch (error) {
228â†’			if (error instanceof ORPCError) throw error;
229â†’			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
230â†’			throw error;
231â†’		}
232â†’	});
