  1â†’import type {
  2â†’	ModelTokensTrendData,
  3â†’	OverviewKPIs,
  4â†’	UsageTrendData,
  5â†’} from "@rudel/api-routes";
  6â†’import {
  7â†’	buildDateFilter,
  8â†’	escapeString,
  9â†’	queryClickhouse,
 10â†’} from "../clickhouse.js";
 11â†’
 12â†’export interface Insight {
 13â†’	type: "trend" | "performer" | "alert" | "info";
 14â†’	severity: "positive" | "warning" | "negative" | "info";
