 19â†’/**
 20â†’ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 21â†’ */
 22â†’export async function getOverviewKPIs(
 23â†’	orgId: string,
 24â†’	days = 7,
 25â†’): Promise<OverviewKPIs> {
 26â†’	const org = escapeString(orgId);
 27â†’	const dateFilter = buildDateFilter(days);
 28â†’
 29â†’	const query = `
 30â†’    SELECT
 31â†’      uniq(user_id) as distinct_users,
 32â†’      count() as distinct_sessions,
 33â†’      uniq(if(git_remote != '', git_remote, if(repository != '', repository, project_path))) as distinct_projects,
 34â†’      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
 35â†’      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_skills,
 36â†’      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands
 37â†’    FROM rudel.session_analytics
 38â†’    WHERE ${dateFilter}
 39â†’      AND organization_id = '${org}'
 40â†’  `;
 41â†’
 42â†’	const result = await queryClickhouse<OverviewKPIs>(query);
 43â†’	const row = result[0];
 44â†’	if (!row) {
 45â†’		return {
 46â†’			distinct_users: 0,
 47â†’			distinct_sessions: 0,
 48â†’			distinct_projects: 0,
 49â†’			distinct_subagents: 0,
 50â†’			distinct_skills: 0,
 51â†’			distinct_slash_commands: 0,
 52â†’		};
 53â†’	}
 54â†’	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
 55â†’	return {
 56â†’		distinct_users: Number(row.distinct_users),
 57â†’		distinct_sessions: Number(row.distinct_sessions),
 58â†’		distinct_projects: Number(row.distinct_projects),
 59â†’		distinct_subagents: Number(row.distinct_subagents),
 60â†’		distinct_skills: Number(row.distinct_skills),
 61â†’		distinct_slash_commands: Number(row.distinct_slash_commands),
 62â†’	};
 63â†’}
 64â†’
 65â†’/**
 66â†’ * Get token usage broken down by model and day
 67â†’ */
 68â†’export async function getModelTokensTrend(
 69â†’	orgId: string,
 70â†’	days = 30,
 71â†’): Promise<ModelTokensTrendData[]> {
 72â†’	const org = escapeString(orgId);
 73â†’	const dateFilter = buildDateFilter(days);
 74â†’
 75â†’	const query = `
 76â†’    SELECT
 77â†’      toDate(session_date) as date,
 78â†’      model_used as model,
 79â†’      sum(total_tokens) as total_tokens,
 80â†’      sum(input_tokens) as input_tokens,
 81â†’      sum(output_tokens) as output_tokens
 82â†’    FROM rudel.session_analytics
 83â†’    WHERE ${dateFilter}
 84â†’      AND organization_id = '${org}'
 85â†’      AND model_used != ''
 86â†’      AND model_used != 'unknown'
 87â†’    GROUP BY date, model
