121â†’/**
122â†’ * Generate rule-based insights from current data
123â†’ */
124â†’export async function getOverviewInsights(
125â†’	orgId: string,
126â†’	days = 7,
127â†’): Promise<Insight[]> {
128â†’	const org = escapeString(orgId);
129â†’	const insights: Insight[] = [];
130â†’
131â†’	const currentPeriodQuery = `
132â†’    SELECT
133â†’      count() as total_sessions,
134â†’      uniq(user_id) as total_users,
135â†’      round(avg(actual_duration_min), 2) as avg_duration_min
136â†’    FROM rudel.session_analytics
137â†’    WHERE ${buildDateFilter(days)}
138â†’      AND organization_id = '${org}'
139â†’  `;
140â†’
141â†’	const previousDays = Number(days) * 2;
142â†’	const previousPeriodQuery = `
143â†’    SELECT
144â†’      count() as total_sessions,
145â†’      uniq(user_id) as total_users,
146â†’      round(avg(actual_duration_min), 2) as avg_duration_min
147â†’    FROM rudel.session_analytics
148â†’    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
149â†’      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
150â†’      AND organization_id = '${org}'
151â†’  `;
152â†’
153â†’	interface PeriodStats {
154â†’		total_sessions: number;
155â†’		total_users: number;
156â†’		avg_duration_min: number;
157â†’	}
158â†’
159â†’	const [currentData, previousData] = await Promise.all([
160â†’		queryClickhouse<PeriodStats>(currentPeriodQuery),
161â†’		queryClickhouse<PeriodStats>(previousPeriodQuery),
162â†’	]);
163â†’
164â†’	const current = currentData[0];
165â†’	const previous = previousData[0] || { total_sessions: 0 };
166â†’
167â†’	// Insight 1: Session trend analysis
168â†’	if (current && previous) {
169â†’		const sessionChange =
170â†’			previous.total_sessions > 0
171â†’				? ((current.total_sessions - previous.total_sessions) /
172â†’						previous.total_sessions) *
173â†’					100
174â†’				: 0;
175â†’
176â†’		if (Math.abs(sessionChange) >= 10) {
177â†’			const direction = sessionChange > 0 ? "up" : "down";
178â†’			const severity = sessionChange > 0 ? "positive" : "warning";
179â†’			insights.push({
180â†’				type: "trend",
181â†’				severity,
182â†’				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
183â†’				link: "/dashboard/team",
184â†’			});
185â†’		}
186â†’	}
187â†’
188â†’	// Insight 2: Top performer identification
189â†’	const topPerformerQuery = `
190â†’    SELECT
191â†’      user_id,
192â†’      count() as sessions,
193â†’      round(sum(actual_duration_min) / 60, 1) as total_hours
194â†’    FROM rudel.session_analytics
195â†’    WHERE ${buildDateFilter(days)}
196â†’      AND organization_id = '${org}'
197â†’    GROUP BY user_id
198â†’    ORDER BY sessions DESC
199â†’    LIMIT 1
200â†’  `;
201â†’
202â†’	const topPerformer = await queryClickhouse<{
203â†’		user_id: string;
204â†’		sessions: number;
205â†’		total_hours: number;
206â†’	}>(topPerformerQuery);
207â†’	if (topPerformer.length > 0 && topPerformer[0]) {
208â†’		const performer = topPerformer[0];
209â†’		const { getUserMapping } = await import("./user.service.js");
210â†’		const userMapping = await getUserMapping(orgId, performer.user_id, days);
211â†’		const displayName =
212â†’			userMapping?.username || `${performer.user_id.substring(0, 8)}...`;
213â†’
214â†’		insights.push({
215â†’			type: "performer",
216â†’			severity: "info",
217â†’			message: `Top contributor: ${displayName} (${performer.sessions} sessions, ${performer.total_hours}h)`,
218â†’			link: `/dashboard/developers/${performer.user_id}`,
219â†’		});
220â†’	}
221â†’
222â†’	// Insight 3: Knowledge silos detection
223â†’	const knowledgeSilosQuery = `
224â†’    SELECT
225â†’      project_path,
226â†’      uniq(user_id) as unique_users,
227â†’      count() as sessions
228â†’    FROM rudel.session_analytics
229â†’    WHERE ${buildDateFilter(30)}
230â†’      AND organization_id = '${org}'
231â†’    GROUP BY project_path
232â†’    HAVING unique_users = 1 AND sessions >= 5
233â†’    ORDER BY sessions DESC
234â†’  `;
235â†’
236â†’	const silos = await queryClickhouse<{
237â†’		project_path: string;
238â†’		unique_users: number;
239â†’		sessions: number;
240â†’	}>(knowledgeSilosQuery);
241â†’	if (silos.length > 0) {
242â†’		insights.push({
243â†’			type: "alert",
244â†’			severity: "warning",
245â†’			message: `${silos.length} project${silos.length > 1 ? "s" : ""} with only one developer - risk of knowledge silos`,
246â†’			link: "/dashboard/projects",
247â†’		});
248â†’	}
249â†’
250â†’	return insights.slice(0, 3);
251â†’}
