263â†’export async function getTeamSummaryWithComparison(orgId: string, days = 7) {
264â†’	const org = escapeString(orgId);
265â†’	const previousDays = Number(days) * 2;
266â†’
267â†’	const currentQuery = `
268â†’    SELECT
269â†’      count() as total_sessions,
270â†’      uniq(user_id) as active_users,
271â†’      round(avg(actual_duration_min), 2) as avg_duration_min,
272â†’      round(count() / uniq(user_id), 2) as avg_sessions_per_user
273â†’    FROM rudel.session_analytics
274â†’    WHERE ${buildDateFilter(days)}
275â†’      AND organization_id = '${org}'
276â†’  `;
277â†’
278â†’	const previousQuery = `
279â†’    SELECT
280â†’      count() as total_sessions,
281â†’      uniq(user_id) as active_users,
282â†’      round(avg(actual_duration_min), 2) as avg_duration_min,
283â†’      round(count() / uniq(user_id), 2) as avg_sessions_per_user
284â†’    FROM rudel.session_analytics
285â†’    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
286â†’      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
287â†’      AND organization_id = '${org}'
288â†’  `;
289â†’
290â†’	const [currentData, previousData] = await Promise.all([
291â†’		queryClickhouse<TeamSummaryPeriodData>(currentQuery),
292â†’		queryClickhouse<TeamSummaryPeriodData>(previousQuery),
293â†’	]);
294â†’
295â†’	const defaultPeriod: TeamSummaryPeriodData = {
296â†’		total_sessions: 0,
297â†’		active_users: 0,
298â†’		avg_duration_min: 0,
299â†’		avg_sessions_per_user: 0,
300â†’	};
301â†’
302â†’	const current = currentData[0] || defaultPeriod;
303â†’	const previous = previousData[0] || defaultPeriod;
304â†’
305â†’	const calculateChange = (curr: number, prev: number) => {
306â†’		if (!prev || prev === 0) return 0;
307â†’		return ((curr - prev) / prev) * 100;
308â†’	};
309â†’
310â†’	const changes = {
311â†’		total_sessions: calculateChange(
312â†’			current.total_sessions || 0,
313â†’			previous.total_sessions || 0,
314â†’		),
315â†’		active_users: calculateChange(
316â†’			current.active_users || 0,
317â†’			previous.active_users || 0,
318â†’		),
319â†’		avg_duration_min: calculateChange(
320â†’			current.avg_duration_min || 0,
321â†’			previous.avg_duration_min || 0,
322â†’		),
323â†’		avg_sessions_per_user: calculateChange(
324â†’			current.avg_sessions_per_user || 0,
325â†’			previous.avg_sessions_per_user || 0,
326â†’		),
327â†’	};
328â†’
329â†’	return { current, previous, changes };
330â†’}
