  1â†’import { createClient } from "@clickhouse/client-web";
  2â†’import { getLogger } from "@logtape/logtape";
  3â†’
  4â†’const logger = getLogger(["rudel", "api", "clickhouse"]);
  5â†’
  6â†’export interface ClickHouseExecutor {
  7â†’	execute(sql: string): Promise<void>;
  8â†’	query<T>(sql: string): Promise<T[]>;
  9â†’	insert(params: { table: string; values: object[] }): Promise<void>;
 10â†’}
 11â†’
 12â†’export function createClickHouseExecutor(config: {
 13â†’	url: string;
 14â†’	username?: string;
 15â†’	password?: string;
 16â†’	database?: string;
 17â†’}): ClickHouseExecutor {
 18â†’	const client = createClient({
 19â†’		url: config.url,
 20â†’		username: config.username,
 21â†’		password: config.password,
 22â†’		database: config.database,
 23â†’		request_timeout: 120_000,
 24â†’		clickhouse_settings: {
 25â†’			wait_end_of_query: 1,
 26â†’		},
 27â†’	});
 28â†’	return {
 29â†’		async execute(sql) {
 30â†’			await client.command({ query: sql });
 31â†’		},
 32â†’		async query<T>(sql: string): Promise<T[]> {
 33â†’			const result = await client.query({
 34â†’				query: sql,
 35â†’				format: "JSONEachRow",
 36â†’			});
 37â†’			return result.json();
 38â†’		},
 39â†’		async insert(params) {
 40â†’			// Use command() with FORMAT JSONEachRow instead of client.insert()
 41â†’			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 42â†’			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
 43â†’			await client.command({
 44â†’				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
 45â†’			});
 46â†’		},
 47â†’	};
 48â†’}
 49â†’
 50â†’let _clickhouse: ClickHouseExecutor | null = null;
 51â†’
 52â†’export function getClickhouse(): ClickHouseExecutor {
 53â†’	if (!_clickhouse) {
 54â†’		const executor = createClickHouseExecutor({
 55â†’			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 56â†’			username:
 57â†’				process.env.CLICKHOUSE_USERNAME ||
 58â†’				process.env.CLICKHOUSE_USER ||
 59â†’				"default",
 60â†’			password: process.env.CLICKHOUSE_PASSWORD || "",
 61â†’			database: "default",
 62â†’		});
 63â†’		const maxRetries = 3;
 64â†’		_clickhouse = {
 65â†’			...executor,
 66â†’			async insert(params) {
 67â†’				for (let attempt = 0; attempt < maxRetries; attempt++) {
 68â†’					try {
 69â†’						return await executor.insert(params);
 70â†’					} catch (error) {
 71â†’						if (attempt === maxRetries - 1) {
 72â†’							logger.error(
 73â†’								"Insert into {table} failed after {maxRetries} attempts: {error}",
 74â†’								{ table: params.table, maxRetries, error },
 75â†’							);
 76â†’							throw error;
 77â†’						}
 78â†’						logger.warn(
 79â†’							"Insert into {table} failed (attempt {attempt}/{maxRetries}), retrying: {error}",
 80â†’							{
 81â†’								table: params.table,
 82â†’								attempt: attempt + 1,
 83â†’								maxRetries,
 84â†’								error,
 85â†’							},
 86â†’						);
 87â†’						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
 88â†’					}
 89â†’				}
 90â†’			},
 91â†’		};
 92â†’	}
 93â†’	return _clickhouse;
 94â†’}
 95â†’
 96â†’export function escapeString(value: string): string {
 97â†’	return value.replace(/'/g, "\\'");
 98â†’}
 99â†’
100â†’export function buildDateFilter(days: number, column = "session_date"): string {
101â†’	return `${column} >= now64(3) - INTERVAL ${Number(days)} DAY AND ${column} <= now64(3)`;
102â†’}
103â†’
104â†’export async function queryClickhouse<T>(sql: string): Promise<T[]> {
105â†’	const ch = getClickhouse();
106â†’	return ch.query<T>(sql);
107â†’}
