17â†’interface OrganizationContextType {
18â†’	activeOrg: Organization | null;
19â†’	organizations: readonly Organization[];
20â†’	switchOrg: (orgId: string) => Promise<void>;
21â†’	isLoading: boolean;
22â†’}
