28â†’export function OrganizationProvider({ children }: { children: ReactNode }) {
29â†’	const { data: activeOrg, isPending: activeLoading } =
30â†’		authClient.useActiveOrganization();
31â†’	const { data: orgs, isPending: listLoading } =
32â†’		authClient.useListOrganizations();
33â†’	const [switching, setSwitching] = useState(false);
34â†’
35â†’	// Auto-set active org if none is set but user has orgs
36â†’	useEffect(() => {
37â†’		if (
38â†’			!activeLoading &&
39â†’			!listLoading &&
40â†’			!activeOrg &&
41â†’			orgs &&
42â†’			orgs.length > 0 &&
43â†’			!switching
44â†’		) {
45â†’			setSwitching(true);
46â†’			authClient.organization
47â†’				.setActive({ organizationId: orgs[0].id })
48â†’				.finally(() => setSwitching(false));
49â†’		}
50â†’	}, [activeOrg, orgs, activeLoading, listLoading, switching]);
51â†’
52â†’	const switchOrg = async (orgId: string) => {
53â†’		setSwitching(true);
54â†’		try {
55â†’			await authClient.organization.setActive({ organizationId: orgId });
56â†’		} finally {
57â†’			setSwitching(false);
58â†’		}
59â†’	};
60â†’
61â†’	return (
62â†’		<OrganizationContext.Provider
63â†’			value={{
64â†’				activeOrg: activeOrg ?? null,
65â†’				organizations: orgs ?? [],
66â†’				switchOrg,
67â†’				isLoading: activeLoading || listLoading || switching,
68â†’			}}
69â†’		>
70â†’			{children}
71â†’		</OrganizationContext.Provider>
72â†’	);
73â†’}
74â†’
75â†’export function useOrganization() {
76â†’	const context = useContext(OrganizationContext);
77â†’	if (context === undefined) {
78â†’		throw new Error(
79â†’			"useOrganization must be used within an OrganizationProvider",
80â†’		);
81â†’	}
82â†’	return context;
83â†’}
