103â†’export function DatePicker({
104â†’	startDate,
105â†’	endDate,
106â†’	onStartDateChange,
107â†’	onEndDateChange,
108â†’}: DatePickerProps) {
109â†’	const [open, setOpen] = useState(false);
110â†’	const [tempStartDate, setTempStartDate] = useState(startDate);
111â†’	const [tempEndDate, setTempEndDate] = useState(endDate);
112â†’
113â†’	useEffect(() => {
114â†’		setTempStartDate(startDate);
115â†’		setTempEndDate(endDate);
116â†’	}, [startDate, endDate]);
117â†’
118â†’	const handleOpenChange = (nextOpen: boolean) => {
119â†’		setOpen(nextOpen);
120â†’		if (!nextOpen) {
121â†’			setTempStartDate(startDate);
122â†’			setTempEndDate(endDate);
123â†’		}
124â†’	};
125â†’
126â†’	const handleApply = () => {
127â†’		onStartDateChange(tempStartDate);
128â†’		onEndDateChange(tempEndDate);
129â†’		setOpen(false);
130â†’	};
131â†’
132â†’	const handlePresetClick = (preset: DatePreset) => {
133â†’		const { start, end } = preset.getValue();
134â†’		setTempStartDate(start);
135â†’		setTempEndDate(end);
136â†’		onStartDateChange(start);
137â†’		onEndDateChange(end);
138â†’		setOpen(false);
139â†’	};
140â†’
141â†’	const formatDateRange = () => {
142â†’		const start = new Date(startDate);
143â†’		const end = new Date(endDate);
144â†’		const startStr = start.toLocaleDateString("en-US", {
145â†’			month: "short",
146â†’			day: "numeric",
147â†’		});
148â†’		const endStr = end.toLocaleDateString("en-US", {
149â†’			month: "short",
150â†’			day: "numeric",
151â†’			year: "numeric",
152â†’		});
153â†’		return `${startStr} - ${endStr}`;
154â†’	};
155â†’
156â†’	return (
157â†’		<Popover open={open} onOpenChange={handleOpenChange}>
158â†’			<PopoverTrigger asChild>
159â†’				<Button variant="outline" className="gap-2">
160â†’					<Calendar className="h-4 w-4 text-muted" />
161â†’					<span className="text-sm font-medium">{formatDateRange()}</span>
162â†’				</Button>
163â†’			</PopoverTrigger>
164â†’			<PopoverContent className="w-auto p-0" align="end">
165â†’				<div className="flex overflow-hidden">
166â†’					<div className="w-40 border-r border-border bg-surface">
167â†’						{DATE_PRESETS.map((preset) => (
168â†’							<button
169â†’								key={preset.label}
170â†’								type="button"
171â†’								onClick={() => handlePresetClick(preset)}
172â†’								className="w-full text-left px-4 py-2 text-sm text-foreground hover:bg-accent-light hover:text-accent-text transition-colors"
173â†’							>
174â†’								{preset.label}
175â†’							</button>
176â†’						))}
177â†’					</div>
178â†’
179â†’					<div className="p-4 w-64">
180â†’						<div className="space-y-3">
181â†’							<div>
182â†’								<Label
183â†’									htmlFor="date-picker-start"
184â†’									className="text-xs text-muted mb-1"
185â†’								>
186â†’									Start date
187â†’								</Label>
188â†’								<Input
189â†’									id="date-picker-start"
190â†’									type="date"
191â†’									value={tempStartDate}
192â†’									onChange={(e) => setTempStartDate(e.target.value)}
193â†’									max={tempEndDate}
194â†’								/>
195â†’							</div>
196â†’
197â†’							<div>
198â†’								<Label
199â†’									htmlFor="date-picker-end"
200â†’									className="text-xs text-muted mb-1"
201â†’								>
202â†’									End date
203â†’								</Label>
204â†’								<Input
205â†’									id="date-picker-end"
206â†’									type="date"
207â†’									value={tempEndDate}
208â†’									onChange={(e) => setTempEndDate(e.target.value)}
209â†’									min={tempStartDate}
210â†’									max={new Date().toISOString().split("T")[0]}
211â†’								/>
212â†’							</div>
213â†’
214â†’							<div className="pt-2">
215â†’								<Button className="w-full" onClick={handleApply}>
216â†’									Apply
217â†’								</Button>
218â†’							</div>
219â†’						</div>
220â†’					</div>
221â†’				</div>
222â†’			</PopoverContent>
223â†’		</Popover>
224â†’	);
225â†’}
