 23â†’	orgId: string,
 24â†’	days = 7,
 25â†’): Promise<OverviewKPIs> {
 26â†’	const org = escapeString(orgId);
 27â†’	const dateFilter = buildDateFilter(days);
 28â†’
 29â†’	const query = `
 30â†’    SELECT
 31â†’      uniq(user_id) as distinct_users,
 32â†’      count() as distinct_sessions,
 33â†’      uniq(if(git_remote != '', git_remote, if(repository != '', repository, project_path))) as distinct_projects,
