332â†’/**
333â†’ * Get session success rate metrics with comparison
334â†’ */
335â†’export async function getSuccessRateMetrics(orgId: string, days = 7) {
336â†’	const org = escapeString(orgId);
337â†’	const previousDays = Number(days) * 2;
338â†’
339â†’	const currentQuery = `
340â†’    SELECT
341â†’      count() as total_sessions,
342â†’      round(avg(success_score), 1) as avg_success_score,
343â†’      countIf(success_score >= 70) as high_quality_sessions
344â†’    FROM rudel.session_analytics
345â†’    WHERE ${buildDateFilter(days)}
346â†’      AND organization_id = '${org}'
347â†’  `;
348â†’
349â†’	const previousQuery = `
350â†’    SELECT
351â†’      count() as total_sessions,
352â†’      round(avg(success_score), 1) as avg_success_score,
353â†’      countIf(success_score >= 70) as high_quality_sessions
354â†’    FROM rudel.session_analytics
355â†’    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
356â†’      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
357â†’      AND organization_id = '${org}'
358â†’  `;
359â†’
360â†’	interface SuccessRateStats {
361â†’		total_sessions: number;
362â†’		avg_success_score: number;
363â†’		high_quality_sessions: number;
364â†’	}
365â†’
366â†’	const [currentData, previousData] = await Promise.all([
367â†’		queryClickhouse<SuccessRateStats>(currentQuery),
368â†’		queryClickhouse<SuccessRateStats>(previousQuery),
369â†’	]);
370â†’
371â†’	const current: SuccessRateStats = currentData[0] || {
372â†’		total_sessions: 0,
373â†’		avg_success_score: 0,
374â†’		high_quality_sessions: 0,
375â†’	};
376â†’
377â†’	const previous: SuccessRateStats = previousData[0] || {
378â†’		total_sessions: 0,
379â†’		avg_success_score: 0,
380â†’		high_quality_sessions: 0,
381â†’	};
382â†’
383â†’	const currentSuccessRate =
384â†’		current.total_sessions > 0
385â†’			? (current.high_quality_sessions / current.total_sessions) * 100
386â†’			: 0;
387â†’
388â†’	const previousSuccessRate =
389â†’		previous.total_sessions > 0
390â†’			? (previous.high_quality_sessions / previous.total_sessions) * 100
391â†’			: 0;
392â†’
393â†’	return {
394â†’		current: {
395â†’			high_quality_sessions: current.high_quality_sessions,
396â†’			total_sessions: current.total_sessions,
397â†’			success_rate: currentSuccessRate,
398â†’		},
399â†’		previous: {
400â†’			high_quality_sessions: previous.high_quality_sessions,
401â†’			total_sessions: previous.total_sessions,
402â†’			success_rate: previousSuccessRate,
403â†’		},
404â†’		changes: {
405â†’			success_rate: currentSuccessRate - previousSuccessRate,
406â†’		},
407â†’	};
408â†’}
