 24â†’const formatLocalDate = (date: Date): string => {
 25â†’	const year = date.getFullYear();
 26â†’	const month = String(date.getMonth() + 1).padStart(2, "0");
 27â†’	const day = String(date.getDate()).padStart(2, "0");
 28â†’	return `${year}-${month}-${day}`;
 29â†’};
 30â†’
 31â†’const DATE_PRESETS: DatePreset[] = [
 32â†’	{
 33â†’		label: "Last 7 days",
 34â†’		getValue: () => {
 35â†’			const end = new Date();
 36â†’			const start = new Date();
 37â†’			start.setDate(start.getDate() - 7);
 38â†’			return { start: formatLocalDate(start), end: formatLocalDate(end) };
 39â†’		},
 40â†’	},
 41â†’	{
 42â†’		label: "This week",
